import PostCard from "../components/PostCard";
import Hero from "../components/Hero";
import { getLatestPosts } from "../lib/wp";
import { WPPost } from "../types/wp";

export default async function Home() {
    const posts: WPPost[] = await getLatestPosts(3);

    return (
        <div className="w-full">
            <Hero />

            <div className="max-w-7xl mx-auto py-16 px-4 sm:px-6 lg:px-8">
                <section>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-3xl font-bold text-gray-900 dark:text-white border-b-4 border-accent pb-2 inline-block">Últimas Noticias</h3>
                        <a href="/noticias" className="hidden sm:block text-secondary hover:text-accent font-medium transition-colors">
                            Ver todas →
                        </a>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {posts.length > 0 ? (
                            posts.map((post) => (
                                <PostCard
                                    key={post.id}
                                    title={post.title.rendered}
                                    excerpt={post.excerpt.rendered}
                                    slug={post.slug}
                                    date={post.date}
                                />
                            ))
                        ) : (
                            <p className="text-gray-500 col-span-3 text-center">No se encontraron noticias recientes.</p>
                        )}
                    </div>
                </section>
            </div>
        </div>
    );
}
