import { FaHeart, FaChevronLeft, FaChevronRight } from "react-icons/fa";

export default function Hero() {
    return (
        <section className="relative w-full h-[600px] md:h-[800px] bg-gray-900 flex items-center justify-center overflow-hidden">
            {/* Background Video (Placeholder URL until API is connected) */}
            <video
                className="absolute inset-0 w-full h-full object-cover z-0"
                autoPlay
                loop
                muted
                playsInline
                poster="https://via.placeholder.com/1920x1080/0c2070/ffffff?text=Video+Cargando..."
            >
                {/* Asumimos que más adelante esto vendrá del API de WP. Por ahora usamos un sample open source */}
                <source src="https://www.w3schools.com/html/mov_bbb.mp4" type="video/mp4" />
                Tu navegador no soporta videos HTML5.
            </video>

            {/* Darkened Overlay */}
            <div className="absolute inset-0 bg-black/40 z-10" />

            {/* Left and Right Arrows */}
            <button className="absolute left-4 md:left-8 top-1/2 -translate-y-1/2 z-30 w-12 h-12 bg-black/50 hover:bg-black/70 rounded-full flex items-center justify-center text-white transition-colors">
                <FaChevronLeft className="text-xl" />
            </button>
            <button className="absolute right-4 md:right-8 top-1/2 -translate-y-1/2 z-30 w-12 h-12 bg-black/50 hover:bg-black/70 rounded-full flex items-center justify-center text-white transition-colors">
                <FaChevronRight className="text-xl" />
            </button>

            {/* Content Overlay */}
            <div className="relative z-20 text-center px-4 max-w-5xl mx-auto flex flex-col items-center">
                <div className="relative inline-block mt-8">
                    {/* Floating Heart Icon above 'años' */}
                    <FaHeart className="absolute -top-10 right-4 text-accent text-4xl rotate-12" />

                    <h2 className="text-6xl md:text-8xl lg:text-9xl font-extrabold text-white tracking-tight leading-none drop-shadow-xl" style={{ textShadow: "0 4px 6px rgba(0,0,0,0.5)" }}>
                        <span className="block mb-2">35 años</span>
                        <span className="block">apoyando la inclusión!</span>
                    </h2>
                </div>
            </div>

            {/* Additional bottom element matching the UI (slider indicators) */}
            <div className="absolute bottom-6 md:bottom-12 z-30 flex gap-2">
                <button className="w-3 h-3 rounded-full bg-white ring-2 ring-white/50 ring-offset-2 ring-offset-transparent"></button>
            </div>
        </section>
    );
}
